import{_ as e,c as o,o as t,a2 as a}from"./chunks/framework.DdOM6S6U.js";const f=JSON.parse('{"title":"Forms","description":"","frontmatter":{"sidebarPos":2},"headers":[],"relativePath":"guide/components/forms.md","filePath":"guide/components/forms.md","lastUpdated":null}'),r={name:"guide/components/forms.md"},d=a('<h1 id="forms" tabindex="-1">Forms <a class="header-anchor" href="#forms" aria-label="Permalink to &quot;Forms&quot;">​</a></h1><p>Modularity forms are schema-driven. The backend hydrates module config into a schema; the frontend renders it via FormBase and FormBaseField.</p><h2 id="flow" tabindex="-1">Flow <a class="header-anchor" href="#flow" aria-label="Permalink to &quot;Flow&quot;">​</a></h2><ol><li><strong>Module config</strong> — Define inputs in your module&#39;s <code>config.php</code> (see <a href="/system-reference/hydrates">Hydrates</a>)</li><li><strong>Controller</strong> — <code>setupFormSchema()</code> hydrates the schema before create/edit</li><li><strong>Inertia</strong> — Schema and model are passed to the page</li><li><strong>Form.vue</strong> — Receives <code>schema</code> and <code>modelValue</code>, uses <code>useForm</code></li><li><strong>FormBase</strong> — Flattens schema + model into <code>flatCombinedArraySorted</code>, iterates over each field</li><li><strong>FormBaseField</strong> — Renders each field by <code>obj.schema.type</code> via <code>mapTypeToComponent()</code></li><li><strong>Input components</strong> — Receive schema props via <code>bindSchema(obj)</code></li></ol><h2 id="key-components" tabindex="-1">Key Components <a class="header-anchor" href="#key-components" aria-label="Permalink to &quot;Key Components&quot;">​</a></h2><table><thead><tr><th>Component</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>Form.vue</strong></td><td>Top-level form; validation, submit, schema/model sync</td></tr><tr><td><strong>FormBase</strong></td><td>Iterates over flattened schema; grid layout, slots</td></tr><tr><td><strong>FormBaseField</strong></td><td>Renders a single field; resolves type → component</td></tr><tr><td><strong>CustomFormBase</strong></td><td>Wrapper with app-specific behavior</td></tr></tbody></table><h2 id="schema-structure" tabindex="-1">Schema Structure <a class="header-anchor" href="#schema-structure" aria-label="Permalink to &quot;Schema Structure&quot;">​</a></h2><p>Each field in the schema has:</p><ul><li><code>type</code> — Resolved to Vue component (e.g. <code>input-checklist</code>, <code>text</code>, <code>select</code>)</li><li><code>name</code> — Field name (binds to model)</li><li><code>label</code> — Display label</li><li><code>col</code> — Grid column span</li><li><code>rules</code> — Validation rules</li><li><code>default</code> — Default value</li></ul><p>See <a href="/system-reference/hydrates#schema-contract">Schema Contract</a> for full keys. For config → schema flow per feature, see <a href="/guide/module-features/">Module Features Overview</a>.</p><h2 id="slots" tabindex="-1">Slots <a class="header-anchor" href="#slots" aria-label="Permalink to &quot;Slots&quot;">​</a></h2><p>FormBase provides slots for customization:</p><ul><li><code>form-top</code>, <code>form-bottom</code> — Form-level</li><li><code>{type}-top</code>, <code>{type}-bottom</code> — By schema type (e.g. <code>input-checklist-top</code>)</li><li><code>{key}-top</code>, <code>{key}-bottom</code> — By field name</li><li><code>{type}-item</code>, <code>{key}-item</code> — Override field rendering</li></ul><h2 id="adding-custom-inputs" tabindex="-1">Adding Custom Inputs <a class="header-anchor" href="#adding-custom-inputs" aria-label="Permalink to &quot;Adding Custom Inputs&quot;">​</a></h2><ol><li>Create Vue component in <code>vue/src/js/components/inputs/</code></li><li>Register: <code>registerInputType(&#39;input-my-type&#39;, &#39;VInputMyType&#39;)</code></li><li>Create PHP Hydrate in <code>src/Hydrates/Inputs/</code> (for backend schema)</li></ol><p>See <a href="/system-reference/api#adding-a-new-input-type">Adding a New Input</a>.</p>',16),s=[d];function c(i,n,l,m,p,h){return t(),o("div",null,s)}const g=e(r,[["render",c]]);export{f as __pageData,g as default};
